'use strict';

const TEXT_MIME = /^(text\/|application\/(json|javascript|xml))/i;

function isText(ct = '') {
  return TEXT_MIME.test(ct);
}

async function proxyFetch(url, options = {}) {
  const resp = await fetch(url, options);
  const ct = resp.headers.get('content-type') || '';
  const textBody = isText(ct);
  const payload = textBody
    ? await resp.text()
    : Buffer.from(await resp.arrayBuffer()).toString('base64');

  return {
    statusCode: resp.status,
    headers: Object.fromEntries(resp.headers),
    body: payload,
    isBase64Encoded: !textBody
  };
}

// AWS Lambda
exports.handler = async (event) => {
  try {
    const url =
      event.queryStringParameters?.url ||
      (event.body && JSON.parse(event.body).url);
    if (!url) return { statusCode: 400, body: 'Missing "url" parameter' };

    const method = event.httpMethod || 'GET';
    const options = { method };
    if (method !== 'GET' && event.body) options.body = event.body;

    return await proxyFetch(url, options);
  } catch (err) {
    return { statusCode: 500, body: err.message };
  }
};

// Google Cloud Function / Express
exports.webhookProxy = async (req, res) => {
  try {
    const url = req.query.url || req.body?.url;
    if (!url) return res.status(400).send('Missing "url" parameter');

    const options = {
      method: req.method,
      headers: Object.fromEntries(
        Object.entries(req.headers).filter(([k]) => !/^host$/i.test(k))
      )
    };
    if (req.method !== 'GET' && req.rawBody) options.body = req.rawBody;

    const resp = await fetch(url, options);
    res.status(resp.status);
    resp.headers.forEach((v, k) => res.set(k, v));

    const ct = resp.headers.get('content-type') || '';
    if (isText(ct)) {
      res.send(await resp.text());
    } else {
      res.send(Buffer.from(await resp.arrayBuffer()));
    }
  } catch (err) {
    res.status(500).send(err.message);
  }
};